import{_ as a}from"./chunks/placeholder.DuiHaLuQ.js";import{_ as e,o as r,c as d,ag as o}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"软件包说明","description":"","frontmatter":{"title":"软件包说明"},"headers":[],"relativePath":"hardware/legacy-evb/packages.md","filePath":"hardware/legacy-evb/packages.md","lastUpdated":null}'),i={name:"hardware/legacy-evb/packages.md"};function l(c,t,s,n,h,p){return r(),d("div",null,[...t[0]||(t[0]=[o('<h2 id="概览" tabindex="-1">概览 <a class="header-anchor" href="#概览" aria-label="Permalink to &quot;概览&quot;">​</a></h2><p>在官网下载的SDK包中包含很多资源，为了保障开发者能充分了解并使用它们，下面将分别介绍下它们的功能特点。</p><h3 id="bin目录" tabindex="-1">bin目录 <a class="header-anchor" href="#bin目录" aria-label="Permalink to &quot;bin目录&quot;">​</a></h3><p>该目录下包含体验评估板语音交互能力所需的app以及更新app的批处理脚本。</p><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td>应用名称</td><td>安装载体</td><td>功能</td></tr><tr><td>AIUILauncher</td><td>评估板/核心板</td><td>系统级应用，安装时应push到/system/app/目录下，其主要功能是发送开机广播（开发者应用可监听此广播实现开机启动）、开机后拉起UARTService、ControlService、SmartConfigService服务。</td></tr><tr><td>AIUIProductDemo</td><td>评估板/核心板</td><td>AIUI默认播报程序，包含完整的交互处理逻辑，如评估板的灯光控制、歌曲播报等。</td></tr><tr><td>AIUIService</td><td>评估板/核心板</td><td>AIUI核心服务，包含语音唤醒、端点检测、离线命令词识别以及跟AIUI服务端通信等功能。</td></tr><tr><td>ControlService</td><td>评估板/核心板</td><td>评估板中给ControlClient提供服务的应用程序。</td></tr><tr><td>SmartConfigService</td><td>评估板/核心板</td><td>为评估板开启smartconfig配网的服务程序。</td></tr><tr><td>UARTService</td><td>评估板/核心板</td><td>负责串口通信的服务，作为上位机与评估板之间的通信入口。</td></tr><tr><td>ControlClient</td><td>Android手机</td><td>运行在手机平台的应用，主要功能有：启动wifi配网、配置评估板授权信息以及负责手机端跟评估板之间的局域网通信。</td></tr></tbody></table><p>AIUI评估板中关键应用关系图如下所示：</p><p><img src="'+a+'" alt="" title="原图：./images/kuangjia.png"></p><h3 id="doc目录" tabindex="-1">doc目录 <a class="header-anchor" href="#doc目录" aria-label="Permalink to &quot;doc目录&quot;">​</a></h3><p>该目录下包含核心板数据手册与麦克风设计参考文档。</p><h3 id="lib目录" tabindex="-1">lib目录 <a class="header-anchor" href="#lib目录" aria-label="Permalink to &quot;lib目录&quot;">​</a></h3><p>该目录下包含AIUIServiceKit.jar，开发者可在自己开发的评估板应用中集成该库，用来与AIUIService进行通信。详细使用可参考<a href="/hardware/legacy-evb/aiui-service-kit.html">AIUIServiceKit SDK</a>。</p><h3 id="sample目录" tabindex="-1">sample目录 <a class="header-anchor" href="#sample目录" aria-label="Permalink to &quot;sample目录&quot;">​</a></h3><p>该目录下包含ControlService、ControlClient、AIUIProductDemo、UARTService等应用的源码工程，开发者可在此基础上开发出更多样化的产品。</p><p>Demo工程下提供的AIUIDemo是为演示AIUI接口的基本调用方法，该Demo需要界面操作，安装在评估板或核心板中，可以使用TotalControl或vysor进行操作；AIUIDemo与AIUIProductDemo不能同时安装，二选一即可。AIUIDemo与ControlService也不能同时安装，原因参考<a href="/sdk-dev/basics/params.html">AIUI配置provider</a>。</p><p>UART工程下提供的UARTKit是Android平台下<a href="/hardware/legacy-evb/serial-sdk.html">AIUI串口协议</a>的封装实现；UARTKitCtrDemo是上位机（Android平台）集成<a href="/hardware/legacy-evb/serial-sdk.html">AIUI串口协议</a>的基本实现与调用方法演示程序，开发者可参考此代码实现上位机程序。</p><h3 id="smartconfig目录" tabindex="-1">SmartConfig目录 <a class="header-anchor" href="#smartconfig目录" aria-label="Permalink to &quot;SmartConfig目录&quot;">​</a></h3><p>该目录下包含SmartConfig的示例Demo及集成文档。</p><h3 id="tools-其他工具-目录" tabindex="-1">tools（其他工具）目录 <a class="header-anchor" href="#tools-其他工具-目录" aria-label="Permalink to &quot;tools（其他工具）目录&quot;">​</a></h3><p>该目录下包含在PC端使用adb工具对评估板进行配网的批处理脚本与获取msc日志的配置文件。</p><p>开发者在开发过程中遇到问题，如10120错误，可将msc.cfg放入/sdcard/msc/目录下，重启后复现问题，然后将/sdcard/msc/目录下的所有日志文件pull出来，发送给技术支持分析。</p>',20)])])}const A=e(i,[["render",l]]);export{b as __pageData,A as default};
